'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Replaces double-precision floating-point strided array elements not equal to a provided search element with a specified scalar constant.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {number} searchElement - search element
* @param {number} alpha - scalar constant
* @param {Float64Array} x - input array
* @param {integer} strideX - stride length
* @returns {Float64Array} input array
*
* @example
* import Float64Array from '@stdlib/array-float64';
*
* var x = new Float64Array( [ 0.0, -2.0, 3.0, 0.0, 4.0, -6.0 ] );
*
* dfillNotEqual( 6, 0.0, 5.0, x, 1 );
* // x => <Float64Array>[ 0.0, 5.0, 5.0, 0.0, 5.0, 5.0 ]
*/
function dfillNotEqual( N, searchElement, alpha, x, strideX ) {
	return ndarray( N, searchElement, alpha, x, strideX, stride2offset( N, strideX ) ); // eslint-disable-line max-len
}


// EXPORTS //

export default dfillNotEqual;
